# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration backend that supports user, project,
task and message management, a performance dashboard (completion metrics and
peer ratings) and exportable reports (CSV / PDF).

The module is intentionally dependency-free (standard library only) so it can
run anywhere.  All public accessors return defensive deep copies so callers can
never mutate internal state by holding on to a returned object.
"""

from __future__ import annotations

import copy
import csv
import enum
import io
import json
import threading
from dataclasses import dataclass, field
from datetime import datetime
from typing import Callable, Dict, List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(enum.Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(enum.Enum):
    """Roles a user may hold within the system."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(enum.Enum):
    """Supported export formats."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    """Identifies the kind of report that was generated."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal store -- a thin, lockable container for one entity type
# ---------------------------------------------------------------------------
class _Store:
    """A simple keyed container that shares a lock with its siblings."""

    def __init__(self, lock: threading.RLock) -> None:
        self._lock = lock
        self._items: Dict[int, object] = {}


# ---------------------------------------------------------------------------
# Serialization helpers
# ---------------------------------------------------------------------------
def _csv_cell(value: object) -> str:
    """Render an arbitrary report value as a CSV-safe string."""

    if value is None:
        return ""
    if isinstance(value, enum.Enum):
        return str(value.value)
    if isinstance(value, datetime):
        return value.isoformat()
    if isinstance(value, (dict, list, tuple)):
        try:
            return json.dumps(value, default=str, sort_keys=True)
        except (TypeError, ValueError):
            return str(value)
    return str(value)


def _report_to_csv(report: dict) -> str:
    """Serialize a report dictionary to CSV text.

    Reports that contain a list of homogeneous ``rows`` are written as a table;
    everything else is written as a flat ``field,value`` listing.  Either way
    the output always contains at least a header row.
    """

    output = io.StringIO()
    writer = csv.writer(output)
    rows = report.get("rows")
    if isinstance(rows, list) and rows and all(isinstance(r, dict) for r in rows):
        header: List[str] = []
        for row in rows:
            for key in row.keys():
                if key not in header:
                    header.append(key)
        writer.writerow(header)
        for row in rows:
            writer.writerow([_csv_cell(row.get(col)) for col in header])
    else:
        writer.writerow(["field", "value"])
        for key, value in report.items():
            writer.writerow([key, _csv_cell(value)])
    return output.getvalue()


def _make_pdf(lines: List[str]) -> bytes:
    """Build a minimal, structurally valid single-page PDF document."""

    text_lines = lines if lines else [""]

    content_parts = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
    for index, line in enumerate(text_lines):
        safe = (
            line.replace("\\", r"\\")
            .replace("(", r"\(")
            .replace(")", r"\)")
        )
        if index > 0:
            content_parts.append("T*")
        content_parts.append("({0}) Tj".format(safe))
    content_parts.append("ET")
    content = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        ),
        b"<< /Length "
        + str(len(content)).encode("ascii")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets: List[int] = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += "{0} 0 obj\n".format(number).encode("ascii")
        pdf += body
        pdf += b"\nendobj\n"

    xref_pos = len(pdf)
    count = len(objects) + 1
    pdf += b"xref\n"
    pdf += "0 {0}\n".format(count).encode("ascii")
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    pdf += b"trailer\n"
    pdf += "<< /Size {0} /Root 1 0 R >>\n".format(count).encode("ascii")
    pdf += b"startxref\n"
    pdf += "{0}\n".format(xref_pos).encode("ascii")
    pdf += b"%%EOF\n"
    return bytes(pdf)


# ---------------------------------------------------------------------------
# The manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """In-memory, thread-safe facade over the collaboration domain."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._now: Callable[[], datetime] = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_seq = 0

        # All stores deliberately share a single lock so cross-store
        # operations (e.g. cascading deletes) remain atomic.
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)  # holds ratings
        self.reports = _Store(self._lock)

    # -- internal utilities -------------------------------------------------
    def _next_id(self) -> int:
        self._id_seq += 1
        return self._id_seq

    @staticmethod
    def _clone(obj):
        return copy.deepcopy(obj)

    def _require_user(self, user_id: int) -> User:
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user  # type: ignore[return-value]

    def _require_project(self, project_id: int) -> Project:
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project  # type: ignore[return-value]

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task  # type: ignore[return-value]

    def _require_message(self, message_id: int) -> Message:
        message = self.messages._items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message  # type: ignore[return-value]

    @staticmethod
    def _validate_nonempty(value: str, label: str) -> str:
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("{0} must be a non-empty string".format(label))
        return value.strip()

    @staticmethod
    def _validate_email(email: str) -> str:
        if not isinstance(email, str) or not email.strip():
            raise ValidationError("email must be a non-empty string")
        cleaned = email.strip()
        if "@" not in cleaned:
            raise ValidationError("email must contain '@'")
        return cleaned

    def _username_taken(self, username: str, exclude_id: Optional[int]) -> bool:
        for uid, user in self.users._items.items():
            if uid == exclude_id:
                continue
            if user.username == username:  # type: ignore[attr-defined]
                return True
        return False

    def _email_taken(self, email: str, exclude_id: Optional[int]) -> bool:
        for uid, user in self.users._items.items():
            if uid == exclude_id:
                continue
            if user.email == email:  # type: ignore[attr-defined]
                return True
        return False

    def _tasks_for_assignee(self, user_id: int) -> List[Task]:
        return [
            task
            for task in self.tasks._items.values()
            if task.assignee_id == user_id  # type: ignore[attr-defined]
        ]

    # -- user management ----------------------------------------------------
    def register_user(self, username: str, email: str, role: UserRole = UserRole.MEMBER) -> User:
        with self._lock:
            clean_username = self._validate_nonempty(username, "username")
            clean_email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if self._username_taken(clean_username, None):
                raise DuplicateError("username already in use")
            if self._email_taken(clean_email, None):
                raise DuplicateError("email already in use")

            user = User(
                id=self._next_id(),
                username=clean_username,
                email=clean_email,
                role=role,
                created_at=self._now(),
            )
            self.users._items[user.id] = user
            return self._clone(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return self._clone(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [
                self._clone(self.users._items[uid])
                for uid in sorted(self.users._items)
            ]

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            user = self._require_user(user_id)
            if username is not None:
                clean_username = self._validate_nonempty(username, "username")
                if self._username_taken(clean_username, user_id):
                    raise DuplicateError("username already in use")
                user.username = clean_username
            if email is not None:
                clean_email = self._validate_email(email)
                if self._email_taken(clean_email, user_id):
                    raise DuplicateError("email already in use")
                user.email = clean_email
            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                user.role = role
            return self._clone(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            self._require_user(user_id)
            for project in self.projects._items.values():
                if project.owner_id == user_id:  # type: ignore[attr-defined]
                    raise ConflictError("user owns one or more projects")
            for task in self.tasks._items.values():
                if (
                    task.assignee_id == user_id  # type: ignore[attr-defined]
                    and task.status != TaskStatus.COMPLETED  # type: ignore[attr-defined]
                ):
                    raise ConflictError("user has open assigned tasks")
            del self.users._items[user_id]

    # -- project management -------------------------------------------------
    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        with self._lock:
            clean_name = self._validate_nonempty(name, "project name")
            if end_date < start_date:
                raise ValidationError("end_date must not be before start_date")
            self._require_user(owner_id)

            project = Project(
                id=self._next_id(),
                name=clean_name,
                description=description if description is not None else "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects._items[project.id] = project
            return self._clone(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return self._clone(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                self._clone(self.projects._items[pid])
                for pid in sorted(self.projects._items)
            ]

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
        description: Optional[str] = None,
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)
            new_name = project.name
            if name is not None:
                new_name = self._validate_nonempty(name, "project name")
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date must not be before start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description
            return self._clone(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._require_project(project_id)
            task_ids = [
                tid
                for tid, task in self.tasks._items.items()
                if task.project_id == project_id  # type: ignore[attr-defined]
            ]
            for tid in task_ids:
                del self.tasks._items[tid]

            message_ids = [
                mid
                for mid, message in self.messages._items.items()
                if message.project_id == project_id  # type: ignore[attr-defined]
                or message.task_id in task_ids  # type: ignore[attr-defined]
            ]
            for mid in message_ids:
                del self.messages._items[mid]

            del self.projects._items[project_id]

    # -- task management ----------------------------------------------------
    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
    ) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            clean_title = self._validate_nonempty(title, "task title")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not be before project start")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=clean_title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks._items[task.id] = task
            return self._clone(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return self._clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            tasks = [
                task
                for task in self.tasks._items.values()
                if task.project_id == project_id  # type: ignore[attr-defined]
            ]
            tasks.sort(key=lambda t: t.id)
            return [self._clone(task) for task in tasks]

    def list_tasks_by_assignee(self, user_id: int) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            tasks.sort(key=lambda t: t.id)
            return [self._clone(task) for task in tasks]

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            task.assignee_id = assignee_id
            return self._clone(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            task.assignee_id = None
            return self._clone(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline must not be before project start")
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return self._clone(task)

    # -- messaging ----------------------------------------------------------
    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        attachments: Optional[List] = None,
        parent_id: Optional[int] = None,
    ) -> Message:
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_specs = list(attachments) if attachments else []
            body_text = body if isinstance(body, str) else ""
            if not body_text.strip() and not attachment_specs:
                raise ValidationError("message must have a body or attachments")

            now = self._now()
            built_attachments = [
                self._build_attachment(filename, data, author_id, now)
                for filename, data in attachment_specs
            ]

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body_text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built_attachments,
                created_at=now,
                edited_at=None,
            )
            self.messages._items[message.id] = message
            return self._clone(message)

    @staticmethod
    def _build_attachment(filename: str, data, uploaded_by: int, when: datetime) -> Attachment:
        if not isinstance(filename, str) or not filename.strip():
            raise ValidationError("attachment filename must be non-empty")
        try:
            size = len(data)
        except TypeError:
            size = 0
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploaded_by,
            uploaded_at=when,
        )

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("message body must be non-empty")
            message.body = new_body
            message.edited_at = self._now()
            return self._clone(message)

    def add_attachment(self, message_id: int, user_id: int, filename: str, data) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may attach files")
            attachment = self._build_attachment(filename, data, user_id, self._now())
            message.attachments.append(attachment)
            return self._clone(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            messages = [
                message
                for message in self.messages._items.values()
                if message.project_id == project_id  # type: ignore[attr-defined]
            ]
            messages.sort(key=lambda m: m.id)
            return [self._clone(message) for message in messages]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            messages = [
                message
                for message in self.messages._items.values()
                if message.task_id == task_id  # type: ignore[attr-defined]
            ]
            messages.sort(key=lambda m: m.id)
            return [self._clone(message) for message in messages]

    def delete_message(self, message_id: int, user_id: int) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete this message")
            del self.messages._items[message_id]

    # -- performance dashboard ---------------------------------------------
    def _completed_tasks_for(self, user_id: int) -> List[Task]:
        return [
            task
            for task in self._tasks_for_assignee(user_id)
            if task.status == TaskStatus.COMPLETED
        ]

    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = []
            for task in self._completed_tasks_for(user_id):
                if task.started_at is not None and task.completed_at is not None:
                    durations.append(
                        (task.completed_at - task.started_at).total_seconds()
                    )
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback if feedback is not None else "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._items[rating.id] = rating
            return self._clone(rating)

    def _ratings_for(self, user_id: int) -> List[Rating]:
        ratings = [
            rating
            for rating in self.performance._items.values()
            if rating.ratee_id == user_id  # type: ignore[attr-defined]
        ]
        ratings.sort(key=lambda r: r.id)
        return ratings

    def get_ratings_summary(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [self._clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            completion_rate = (completed / total) if total else 0.0

            durations = [
                (t.completed_at - t.started_at).total_seconds()
                for t in tasks
                if t.status == TaskStatus.COMPLETED
                and t.started_at is not None
                and t.completed_at is not None
            ]
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )

            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # -- reports ------------------------------------------------------------
    @staticmethod
    def _summarize_tasks(tasks: List[Task]) -> dict:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
        not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        average_completion_time = (
            sum(durations) / len(durations) if durations else None
        )
        return {
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": average_completion_time,
        }

    def project_progress_report(self, project_id: int) -> dict:
        with self._lock:
            self._require_project(project_id)
            tasks = [
                task
                for task in self.tasks._items.values()
                if task.project_id == project_id  # type: ignore[attr-defined]
            ]
            now = self._now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, dict] = {}
            completed = 0
            for task in tasks:
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id, {"total": 0, "completed": 0}
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            total = len(tasks)
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id: Optional[int] = None) -> dict:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                project_tasks = [
                    task
                    for task in self.tasks._items.values()
                    if task.project_id == project_id  # type: ignore[attr-defined]
                ]
                assignee_ids = sorted(
                    {
                        task.assignee_id
                        for task in project_tasks
                        if task.assignee_id is not None
                    }
                )
                tasks_by_user = {
                    uid: [t for t in project_tasks if t.assignee_id == uid]
                    for uid in assignee_ids
                }
            else:
                assignee_ids = sorted(self.users._items)
                tasks_by_user = {
                    uid: self._tasks_for_assignee(uid) for uid in assignee_ids
                }

            rows = []
            for uid in assignee_ids:
                user = self.users._items.get(uid)
                summary = self._summarize_tasks(tasks_by_user[uid])
                ratings = self._ratings_for(uid)
                rating_count = len(ratings)
                rating_average = (
                    sum(r.score for r in ratings) / rating_count
                    if rating_count
                    else 0.0
                )
                row = {
                    "user_id": uid,
                    "username": user.username if user is not None else "",
                    "total_tasks": summary["total_tasks"],
                    "completed_tasks": summary["completed_tasks"],
                    "in_progress_tasks": summary["in_progress_tasks"],
                    "not_started_tasks": summary["not_started_tasks"],
                    "completion_rate": summary["completion_rate"],
                    "average_completion_time": summary["average_completion_time"],
                    "rating_count": rating_count,
                    "rating_average": rating_average,
                }
                rows.append(row)

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            tasks.sort(key=lambda t: t.id)
            summary = self._summarize_tasks(tasks)
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                }
                for t in tasks
            ]

            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }
            report.update(summary)
            return report

    def export_report(self, report: dict, fmt: ReportFormat):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be a ReportFormat")

            if fmt == ReportFormat.CSV:
                return _report_to_csv(report)
            return self._report_to_pdf(report)

    @staticmethod
    def _report_to_pdf(report: dict) -> bytes:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "rows" and isinstance(value, list):
                lines.append("rows:")
                for row in value:
                    lines.append("  " + _csv_cell(row))
            else:
                lines.append("{0}: {1}".format(key, _csv_cell(value)))
        return _make_pdf(lines)


